"""
FAANG Stock Prediction — ML Dashboard
Streamlit + Groq AI Edition
======================================

HOW TO DEPLOY ON STREAMLIT CLOUD
---------------------------------
1. Put ONLY this file (app.py) in your GitHub repo root
2. Go to share.streamlit.io → New app → select repo → main file: app.py
3. In Streamlit Cloud → App settings → Secrets, add:
       GROQ_API_KEY = "gsk_xxxxxxxxxxxxxxxxxxxx"
4. Deploy!

HOW TO RUN LOCALLY
------------------
    pip install streamlit
    streamlit run app.py

requirements.txt (create this in the same repo):
    streamlit>=1.32.0
"""

import base64
import streamlit as st
import streamlit.components.v1 as components

st.set_page_config(
    page_title="FAANG Stock Prediction — ML Dashboard",
    page_icon="📈",
    layout="wide",
    initial_sidebar_state="expanded",
)

# ── Hide Streamlit chrome for a cleaner look ──────────────────────────────────
st.markdown("""
<style>
  #MainMenu {visibility: hidden;}
  footer {visibility: hidden;}
  .stAppDeployButton {display: none;}
  section[data-testid="stSidebar"] > div {padding-top: 1rem;}
  .block-container {padding: 0 !important; max-width: 100% !important;}
</style>
""", unsafe_allow_html=True)

# ── Sidebar ───────────────────────────────────────────────────────────────────
with st.sidebar:
    st.markdown("## 📈 FAANG ML Dashboard")
    st.divider()
    st.markdown("### 🔑 Groq API Key")
    st.markdown(
        "Required for the **💬 AI Analyst** tab.  \n"
        "[Get a free key at console.groq.com →](https://console.groq.com)"
    )

    # Try Streamlit secrets first, then let user paste it
    default_key = ""
    try:
        default_key = st.secrets.get("GROQ_API_KEY", "")
    except Exception:
        pass

    groq_key = st.text_input(
        "Groq API Key",
        value=default_key,
        type="password",
        placeholder="gsk_xxxxxxxxxxxxxxxxxxxx",
        help="Your key is never stored — it lives only in this browser session.",
        label_visibility="collapsed",
    )

    if groq_key:
        st.success("✅ Key active — AI chat enabled")
    else:
        st.warning("⚠️ No key — AI chat disabled")

    st.divider()
    st.markdown("**AI Model:** `llama-3.3-70b-versatile`")
    st.markdown("**Provider:** [Groq](https://groq.com)")
    st.markdown("**Dataset:** 14,964 samples · 6 tickers · 2016–2026")
    st.divider()
    st.caption("Enter your Groq key above, then click the 💬 AI Analyst tab inside the dashboard.")

# ── Decode the embedded dashboard HTML ───────────────────────────────────────
_HTML_B64 = """"""

_html_bytes = base64.b64decode(_HTML_B64)
_dashboard_html = _html_bytes.decode("utf-8")

# ── Inject the Groq key into the dashboard JavaScript ────────────────────────
_safe_key = groq_key.replace("\\", "").replace('"', "").replace("'", "").replace("\n", "")

KEY_INJECTION = f"""
<script>
  // Injected by Streamlit — sets the Groq API key before the dashboard JS runs
  window.STREAMLIT_GROQ_KEY = "{_safe_key}";
</script>
"""

# Insert injection right after <body> tag
_dashboard_html = _dashboard_html.replace("<body>", "<body>" + KEY_INJECTION, 1)

# ── Update the api-notice panel based on key presence ────────────────────────
if groq_key:
    _dashboard_html = _dashboard_html.replace(
        "KEY LOADED VIA SIDEBAR",
        "✅ KEY ACTIVE"
    )

# ── Render ────────────────────────────────────────────────────────────────────
components.html(_dashboard_html, height=1100, scrolling=True)
